const raw = $input.first().json;
const outputText = (raw.output ?? JSON.stringify(raw)).trim();

// Parse agent output — strip markdown fences if present
let parsed;
try {
  const clean = outputText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '');
  parsed = JSON.parse(clean);
  if (Array.isArray(parsed)) parsed = parsed[0] ?? parsed;
} catch {
  return [{ json: { output: outputText, parse_error: true } }];
}

const fields = parsed.fields ?? {};
const isMissing = (f) => !f || f.value === null || f.value === undefined || f.value === '';

const terms_found = Object.keys(fields).filter(k => !isMissing(fields[k]));
const terms_missing = Object.keys(fields).filter(k => isMissing(fields[k]));

// Risk score derived entirely from risk_weight values the agent carried through from the playbook
const totalWeight = Object.values(fields).reduce((s, f) => s + (f.risk_weight ?? 0), 0);
const missingWeight = terms_missing.reduce((s, k) => s + (fields[k]?.risk_weight ?? 0), 0);
const risk_score = totalWeight > 0
  ? Math.round(100 * (1 - missingWeight / totalWeight))
  : 100;

// Risk flags for missing fields — severity driven by risk_weight from the playbook
// weight >= 8 → high, 5–7 → medium, < 5 → low
const risk_flags = terms_missing.map(key => {
  const w = fields[key]?.risk_weight ?? 0;
  const severity = w >= 8 ? 'high' : w >= 5 ? 'medium' : 'low';
  return {
    id: `missing_${key}`,
    severity,
    title: `${key.replace(/_/g, ' ')} not found`,
    description: `This field was not found in the contract. ${severity === 'high' ? 'Required for IFRS 16 compliance — resolve before exporting.' : 'Verify manually.'}`,
    field: key,
  };
});

return [{
  json: {
    contract_type: parsed.contract_type ?? 'LEASE',
    terms_found,
    terms_missing,
    risk_score,
    analyzed_at: new Date().toISOString(),
    fields,
    risk_flags,
  }
}];
